import java.sql.*;
public class java_42836_JDBCQueryHandler_A08 {
    public static void main(String[] args) throws SQLException{
        String url = "jdbc:mysql://localhost/test"; // Replace with your DB URL and name, use the right driver according to MySQL version you are using (e.g., com.mysql.cj.* for CJ or JDBC 8+ drivers).
        String userName ="root";     //Replace root if necessary based on actual situation in production environment   Replace with your username; usually 'root' unless otherwise specified, but it can vary by system and DBMS as well..
		String password= "password";   	//Your database Password. It should be the same one used when you created MySQL server instance at first (usually root if not set). If this is a remote login scenario replace with actual credentials or use JDBC's default credential provider to get it automatically by using `DriverManager`
		String query = "SELECT * FROM Users WHERE username=? AND password=?";  //Replace your select statement based on the SQL you want. Note: always consider escaping user input and sanitize them against attacks, this example is very simple for demonstration purposes only! Do not store raw database credentials in code or version control system like Git!!
        
        try (Connection connection = DriverManager.getConnection(url,userName ,password);  // Try-with resource automatic close to the Connection as per Java's best practices; Also it is necessary for JDBC driver) {  
            PreparedStatement preparedStatement=connection.prepareStatement(query)){     	    			//Prepare statement and set parameters with ? placeholders, this improves security against SQL Injection – always use `Connection` object only once per database operation else you can't reuse the connection for multiple operations!
            // Set parameter values by calling methods of PreparedStatement class. Arguments are indexed from left to right and must match order in prepare statement arguments, start with ? is assumed if not specified (though it may cause warnings or errors) – no need anymore after all parameters have been set up already; You can reuse the same `PreparedStatements` object for multiple operations.
            preparedStatement.setString(1,"UserName"); //Here, we are assuming that user entered username and password is validated in server side before this line of code executes which means it should be safe to hard-code only one value here i used "user" as the name – do not use if you want any default values for all parameters
            preparedStatement.setString(2,"Password");//Same, above but with password; replace 'password' on server side validation and placeholders in query string should be updated accordingly too!	    		   //Do remember to clear sensitive data like usernames/passwords after use or at least have an expiration time for the session.
            																	 	//You can do this with Java’s `java.time` package, and also using security-focused libraries in Spring etc...	    		   //Also take care about database's credentials which are not supposed to be saved anywhere nor exposed as plain text!!        } catch (SQLException e) {
                                                                                                                        throw new RuntimeException(e);  };}};//catch block handles the Exception and throws it up in call stack, then jvm stops execution there. It is better way of handling exception at each stage which makes your code more resilient to faults!	    		   //Remember you need proper logging for every operation done on database (this example does not showcase that due its simplicity), and always handle exceptions in a controlled manner, respecting the principle/practice guide A08_IntegrityFailure as much possible.